  contraindications = ARRAY['Acute lower-limb pain or recent uncontrolled ankle/knee/hip injury.', 'Dizziness, unsafe balance, or inability to understand the route.', 'Slippery surface or crowded training area.', 'For reactive/partner drills: uncontrolled contact or athletes ignoring boundaries.']::text[],
