-- Lateral Shuffle-to-Stick (lateral-shuffle-to-stick)
UPDATE coaching.exercise SET
  name = 'Lateral Shuffle-to-Stick',
  description = 'Lateral Shuffle-to-Stick is a cone-based athletic drill focused on lateral braking, hip control, and outside-foot pressure. Two cones 5-7 yards apart; shuffle to the cone and freeze. It belongs in the library because it is easy to set up, easy to coach, and scalable from youth development to advanced field/court athletes.',
  card_summary = 'Cone drill for lateral braking, hip control, and outside-foot pressure. Best when coached as Resilience with the drill dose matched to the session phase.',
  coach_language = 'Primary phase: Resilience. Primary subrole: single_leg_balance_foot_ankle_hip_control. Control, braking, and tissue tolerance; speed is secondary to clean ownership. Progress only when the route, posture, and stop/cut quality are repeatable.',
  athlete_language = 'Move in under control, stick the stop, and own the position.',
  movement_family = 'Cone Braking Control',
  primary_phase_key = 'resilience',
  phase_subrole = 'single_leg_balance_foot_ankle_hip_control',
  primary_order_slot = 'lateral_deceleration_stick',
  participant_structure = 'individual',
  default_sets = 2,
  default_reps = 3,
  default_work_seconds = NULL,
  default_rest_seconds = 60,
  est_seconds_per_set = 40,
  movement_requirements = '{"primary_joint_actions":["ankle_stiffness","deceleration_braking","hip_flexion_extension","hip_hinge_absorption","knee_flexion_extension"],"primary_tissues":["calves","quadriceps","hamstrings","glutes","adductors"],"primary_motor_control_demands":["braking_control","single_leg_stability","spatial_orientation","visual_navigation"],"postural_shape":"athletic stance with ribs stacked over pelvis during cuts and stops","breathing_demand":"rhythmic; no breath holding during approach, cut, or stop","balance_demand":"dynamic","coordination_demand":"multi-step cone navigation with clean arm-leg timing","impact_level":2}'::jsonb,
  coaching_execution = '{"movement_description":"Lateral Shuffle-to-Stick uses cones to create a clear movement problem: lateral braking, hip control, and outside-foot pressure. Two cones 5-7 yards apart; shuffle to the cone and freeze. The coach selects speed, spacing, and rest so the drill trains resilience rather than junk fatigue.","setup":["Two cones 5-7 yards apart; shuffle to the cone and freeze.","Use a flat, dry surface with at least 3-5 yards of safe run-out beyond the final cone.","Walk the route once so the athlete understands the entry, target, and finish standard."],"execution_steps":["Start in an athletic stance with eyes up and weight balanced through the whole foot.","Accelerate or move toward the target cone under control, then stick the stop for a two-count.","Brake, cut, or turn with hips loaded, knees tracking over toes, and the trunk under control.","Finish through the final cone or stick the final position exactly as prescribed.","Reset fully before the next rep; stop the set if posture, route accuracy, or braking quality fades."],"coach_cues":["Eyes up; see the cone early, not at the last step.","Push the ground away; do not reach and pull with the lead foot.","Load the hip before changing direction.","Quiet shoulders, violent arms when the drill calls for speed.","Win the shape before chasing the time."],"athlete_cues":["See it early.","Brake low and strong.","Push out of the cut.","Fast feet, quiet body."],"breathing_cues":["Breathe naturally during setup.","Do not hold the breath through the cut or stop.","Use one calm breath to reset before the next rep."],"common_faults":["Standing tall into the stop or cut.","Reaching the plant foot too far outside the hip.","Knee collapsing inside the foot.","Looking down at the cone instead of scanning ahead.","Turning quality reps into conditioning volume."],"quality_gate":["Route is correct without coach rescue.","Final stop or turn is balanced with no extra hop unless the drill calls for a run-through.","Knee tracks over toes on the plant leg.","Athlete can repeat the same shape on both sides.","Speed increases only after control is repeatable."],"stop_signs":["Pain in ankle, knee, hip, back, or groin.","Slipping surface or cones sliding into the athlete path.","Repeated uncontrolled knee valgus or trunk collapse.","Athlete cannot remember route or react safely.","Fatigue changes braking mechanics."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Faster COD drills","Reactive agility","Sustained Capacity intervals"],"pairs_well_after":["Dynamic warm-up","Cone March Line","Single-Leg Cone Reach Stick"],"good_for_sessions":["deceleration","general_warmup","landing_prep","resilience"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Athlete has pain or loss of control during warm-up.","Surface is slippery or space is crowded.","The session goal is recovery or restore only."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["https://www.youtube.com/watch?v=CRIgM8L5ObM","https://www.youtube.com/watch?v=rHpyFD_5mnE","https://www.youtube.com/watch?v=F1e7RowRtus","https://www.youtube.com/watch?v=9kCLZ8CURPI"],"internal_notes":["Film one front/diagonal angle and one side angle when possible.","Show the cone layout before the rep.","Capture one slow walk-through, then one quality-speed rep.","For client view, keep the demo focused on setup, route, posture, and stop/cut standard."]}'::jsonb,
  updated_at = now()
WHERE slug = 'lateral-shuffle-to-stick';

