-- Shuffle-Sprint-Brake Combo (shuffle-sprint-brake-combo)
UPDATE coaching.exercise SET
  name = 'Shuffle-Sprint-Brake Combo',
  description = 'Shuffle-Sprint-Brake Combo is a cone-based athletic drill focused on transition from lateral movement to sprint and controlled stop. Three cones in a line or shallow angle: shuffle, turn sprint, then brake. It belongs in the library because it is easy to set up, easy to coach, and scalable from youth development to advanced field/court athletes.',
  card_summary = 'Cone drill for transition from lateral movement to sprint and controlled stop. Best when coached as Output with the drill dose matched to the session phase.',
  coach_language = 'Primary phase: Output. Primary subrole: deceleration_cod_power. High intent, low volume, full rest; tired reps become conditioning rather than power. Progress only when the route, posture, and stop/cut quality are repeatable.',
  athlete_language = 'Attack the cone, brake under control, then explode out clean.',
  movement_family = 'Cone Braking Control',
  primary_phase_key = 'output',
  phase_subrole = 'deceleration_cod_power',
  primary_order_slot = 'combo_deceleration',
  participant_structure = 'individual',
  default_sets = 3,
  default_reps = 2,
  default_work_seconds = NULL,
  default_rest_seconds = 90,
  est_seconds_per_set = 20,
  movement_requirements = '{"primary_joint_actions":["ankle_stiffness","deceleration_braking","hip_flexion_extension","hip_hinge_absorption","knee_flexion_extension"],"primary_tissues":["calves","quadriceps","hamstrings","glutes","adductors"],"primary_motor_control_demands":["braking_control","single_leg_stability","spatial_orientation","visual_navigation"],"postural_shape":"athletic stance with ribs stacked over pelvis during cuts and stops","breathing_demand":"rhythmic; no breath holding during approach, cut, or stop","balance_demand":"dynamic-high-speed","coordination_demand":"multi-step cone navigation with clean arm-leg timing","impact_level":3}'::jsonb,
  coaching_execution = '{"movement_description":"Shuffle-Sprint-Brake Combo uses cones to create a clear movement problem: transition from lateral movement to sprint and controlled stop. Three cones in a line or shallow angle: shuffle, turn sprint, then brake. The coach selects speed, spacing, and rest so the drill trains output rather than junk fatigue.","setup":["Three cones in a line or shallow angle: shuffle, turn sprint, then brake.","Use a flat, dry surface with at least 3-5 yards of safe run-out beyond the final cone.","Walk the route once so the athlete understands the entry, target, and finish standard."],"execution_steps":["Start in an athletic stance with eyes up and weight balanced through the whole foot.","Perform the shuffle-sprint-brake combo route at the prescribed speed while staying inside the cone constraints.","Brake, cut, or turn with hips loaded, knees tracking over toes, and the trunk under control.","Finish through the final cone or stick the final position exactly as prescribed.","Reset fully before the next rep; stop the set if posture, route accuracy, or braking quality fades."],"coach_cues":["Eyes up; see the cone early, not at the last step.","Push the ground away; do not reach and pull with the lead foot.","Load the hip before changing direction.","Quiet shoulders, violent arms when the drill calls for speed.","Win the shape before chasing the time."],"athlete_cues":["See it early.","Brake low and strong.","Push out of the cut.","Fast feet, quiet body."],"breathing_cues":["Breathe naturally during setup.","Do not hold the breath through the cut or stop.","Use one calm breath to reset before the next rep."],"common_faults":["Standing tall into the stop or cut.","Reaching the plant foot too far outside the hip.","Knee collapsing inside the foot.","Looking down at the cone instead of scanning ahead.","Turning quality reps into conditioning volume."],"quality_gate":["Route is correct without coach rescue.","Final stop or turn is balanced with no extra hop unless the drill calls for a run-through.","Knee tracks over toes on the plant leg.","Athlete can repeat the same shape on both sides.","Speed increases only after control is repeatable."],"stop_signs":["Pain in ankle, knee, hip, back, or groin.","Slipping surface or cones sliding into the athlete path.","Repeated uncontrolled knee valgus or trunk collapse.","Athlete cannot remember route or react safely.","Fatigue changes braking mechanics."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Capacity strength","Resilience accessories","Sustained Capacity"],"pairs_well_after":["Dynamic warm-up","Sprint mechanics drills","Linear deceleration stick"],"good_for_sessions":["deceleration","general_warmup","landing_prep","sprint_prep"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Athlete has pain or loss of control during warm-up.","Surface is slippery or space is crowded.","The session goal is recovery or restore only.","Athlete is already fatigued from conditioning, heavy strength, or repeated jumps."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["https://www.youtube.com/watch?v=CRIgM8L5ObM","https://www.youtube.com/watch?v=rHpyFD_5mnE","https://www.youtube.com/watch?v=F1e7RowRtus","https://www.youtube.com/watch?v=9kCLZ8CURPI"],"internal_notes":["Film one front/diagonal angle and one side angle when possible.","Show the cone layout before the rep.","Capture one slow walk-through, then one quality-speed rep.","For client view, keep the demo focused on setup, route, posture, and stop/cut standard."]}'::jsonb,
  updated_at = now()
WHERE slug = 'shuffle-sprint-brake-combo';

