-- Partner Crossover Mirror Box (partner-crossover-mirror-box)
UPDATE coaching.exercise SET
  name = 'Partner Crossover Mirror Box',
  description = 'Partner Crossover Mirror Box is a cone-based athletic drill focused on crossover reaction, hip turn, and partner timing. Four cones make a box or lane; leader can shuffle or crossover while partner mirrors. It belongs in the library because it is easy to set up, easy to coach, and scalable from youth development to advanced field/court athletes.',
  card_summary = 'Cone drill for crossover reaction, hip turn, and partner timing. Best when coached as Movement Intelligence with the drill dose matched to the session phase.',
  coach_language = 'Primary phase: Movement Intelligence. Primary subrole: perception_action_reactive_movement. Technical learning while fresh; quality stops when timing or posture fades. Progress only when the route, posture, and stop/cut quality are repeatable.',
  athlete_language = 'Move smooth, stay balanced, and learn the route before going fast.',
  movement_family = 'Reactive Cone Agility',
  primary_phase_key = 'movement_intelligence',
  phase_subrole = 'perception_action_reactive_movement',
  primary_order_slot = 'partner_mirror_agility',
  participant_structure = 'pairs',
  default_sets = 4,
  default_reps = 1,
  default_work_seconds = 8,
  default_rest_seconds = 75,
  est_seconds_per_set = 20,
  movement_requirements = '{"primary_joint_actions":["ankle_stiffness","hip_flexion_extension","knee_flexion_extension"],"primary_tissues":["calves","quadriceps","hamstrings","glutes","adductors"],"primary_motor_control_demands":["auditory_visual_reaction","perception_action_coupling","spatial_orientation","visual_navigation"],"postural_shape":"athletic stance with ribs stacked over pelvis during cuts and stops","breathing_demand":"rhythmic; no breath holding during approach, cut, or stop","balance_demand":"dynamic","coordination_demand":"multi-step cone navigation with clean arm-leg timing","impact_level":2}'::jsonb,
  coaching_execution = '{"movement_description":"Partner Crossover Mirror Box uses cones to create a clear movement problem: crossover reaction, hip turn, and partner timing. Four cones make a box or lane; leader can shuffle or crossover while partner mirrors. The coach selects speed, spacing, and rest so the drill trains movement intelligence rather than junk fatigue.","setup":["Four cones make a box or lane; leader can shuffle or crossover while partner mirrors.","Use a flat, dry surface with at least 3-5 yards of safe run-out beyond the final cone.","Walk the route once so the athlete understands the entry, target, and finish standard.","Assign clear leader/chaser roles and keep athletes inside the cone boundaries."],"execution_steps":["Start in an athletic stance with eyes up and weight balanced through the whole foot.","Perform the partner crossover mirror box route at teaching speed first, then progress only if rhythm stays clean.","Brake, cut, or turn with hips loaded, knees tracking over toes, and the trunk under control.","Finish through the final cone or stick the final position exactly as prescribed.","Reset fully before the next rep; stop the set if posture, route accuracy, or braking quality fades."],"coach_cues":["Eyes up; see the cone early, not at the last step.","Push the ground away; do not reach and pull with the lead foot.","Load the hip before changing direction.","Quiet shoulders, violent arms when the drill calls for speed.","Win the shape before chasing the time."],"athlete_cues":["See it early.","Brake low and strong.","Push out of the cut.","Fast feet, quiet body."],"breathing_cues":["Breathe naturally during setup.","Do not hold the breath through the cut or stop.","Use one calm breath to reset before the next rep."],"common_faults":["Standing tall into the stop or cut.","Reaching the plant foot too far outside the hip.","Knee collapsing inside the foot.","Looking down at the cone instead of scanning ahead.","Turning quality reps into conditioning volume."],"quality_gate":["Route is correct without coach rescue.","Final stop or turn is balanced with no extra hop unless the drill calls for a run-through.","Knee tracks over toes on the plant leg.","Athlete can repeat the same shape on both sides.","Speed increases only after control is repeatable."],"stop_signs":["Pain in ankle, knee, hip, back, or groin.","Slipping surface or cones sliding into the athlete path.","Repeated uncontrolled knee valgus or trunk collapse.","Athlete cannot remember route or react safely.","Fatigue changes braking mechanics."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Acceleration starts","Planned COD drills","Reactive agility games"],"pairs_well_after":["Prepare & Access raise/mobilize sequence","Cone March Line","A-Skip Through Cone Gates"],"good_for_sessions":["general_warmup","landing_prep","sprint_prep"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Athlete has pain or loss of control during warm-up.","Surface is slippery or space is crowded.","The session goal is recovery or restore only.","Partners cannot maintain safe spacing or follow boundaries."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["https://www.youtube.com/watch?v=Pb15pCX16H8","https://www.youtube.com/watch?v=TFN0oIXfIl4","https://www.youtube.com/watch?v=TZC-Pl_quoc","https://www.youtube.com/watch?v=jJnGQbhbU64"],"internal_notes":["Film one front/diagonal angle and one side angle when possible.","Show the cone layout before the rep.","Capture one slow walk-through, then one quality-speed rep.","For client view, keep the demo focused on setup, route, posture, and stop/cut standard."]}'::jsonb,
  updated_at = now()
WHERE slug = 'partner-crossover-mirror-box';

