-- Cone Gauntlet Quality Intervals (cone-gauntlet-quality-intervals)
UPDATE coaching.exercise SET
  name = 'Cone Gauntlet Quality Intervals',
  description = 'Cone Gauntlet Quality Intervals is a cone-based athletic drill focused on repeat useful cone work under fatigue while maintaining posture. Use 4-6 cones to build a short route; work 15-25 seconds, rest fully enough to keep mechanics safe. It belongs in the library because it is easy to set up, easy to coach, and scalable from youth development to advanced field/court athletes.',
  card_summary = 'Cone drill for repeat useful cone work under fatigue while maintaining posture. Best when coached as Sustained Capacity with the drill dose matched to the session phase.',
  coach_language = 'Primary phase: Sustained Capacity. Primary subrole: conditioning_intervals. Conditioning on purpose late in the session; posture and safety cap the volume. Progress only when the route, posture, and stop/cut quality are repeatable.',
  athlete_language = 'Move fast enough to work, but clean enough to stay safe.',
  movement_family = 'Cone Repeatability',
  primary_phase_key = 'sustained_capacity',
  phase_subrole = 'conditioning_intervals',
  primary_order_slot = 'quality_agility_intervals',
  participant_structure = 'individual',
  default_sets = 5,
  default_reps = NULL,
  default_work_seconds = 20,
  default_rest_seconds = 60,
  est_seconds_per_set = 80,
  movement_requirements = '{"primary_joint_actions":["ankle_stiffness","hip_flexion_extension","knee_flexion_extension"],"primary_tissues":["calves","quadriceps","hamstrings","glutes","adductors"],"primary_motor_control_demands":["spatial_orientation","visual_navigation"],"postural_shape":"athletic stance with ribs stacked over pelvis during cuts and stops","breathing_demand":"rhythmic; no breath holding during approach, cut, or stop","balance_demand":"dynamic","coordination_demand":"multi-step cone navigation with clean arm-leg timing","impact_level":3}'::jsonb,
  coaching_execution = '{"movement_description":"Cone Gauntlet Quality Intervals uses cones to create a clear movement problem: repeat useful cone work under fatigue while maintaining posture. Use 4-6 cones to build a short route; work 15-25 seconds, rest fully enough to keep mechanics safe. The coach selects speed, spacing, and rest so the drill trains sustained capacity rather than junk fatigue.","setup":["Use 4-6 cones to build a short route; work 15-25 seconds, rest fully enough to keep mechanics safe.","Use a flat, dry surface with at least 3-5 yards of safe run-out beyond the final cone.","Walk the route once so the athlete understands the entry, target, and finish standard.","Place this late in the session and set a quality cap before starting."],"execution_steps":["Start in an athletic stance with eyes up and weight balanced through the whole foot.","Move for the prescribed work interval while preserving posture, foot control, and route accuracy.","Brake, cut, or turn with hips loaded, knees tracking over toes, and the trunk under control.","Finish through the final cone or stick the final position exactly as prescribed.","End the interval early if the athlete can no longer brake or turn safely."],"coach_cues":["Eyes up; see the cone early, not at the last step.","Push the ground away; do not reach and pull with the lead foot.","Load the hip before changing direction.","Quiet shoulders, violent arms when the drill calls for speed.","Win the shape before chasing the time."],"athlete_cues":["See it early.","Brake low and strong.","Push out of the cut.","Fast feet, quiet body."],"breathing_cues":["Breathe naturally during setup.","Do not hold the breath through the cut or stop.","Use one calm breath to reset before the next rep."],"common_faults":["Standing tall into the stop or cut.","Reaching the plant foot too far outside the hip.","Knee collapsing inside the foot.","Looking down at the cone instead of scanning ahead.","Turning quality reps into conditioning volume."],"quality_gate":["Route is correct without coach rescue.","Final stop or turn is balanced with no extra hop unless the drill calls for a run-through.","Knee tracks over toes on the plant leg.","Athlete can repeat the same shape on both sides.","Speed increases only after control is repeatable."],"stop_signs":["Pain in ankle, knee, hip, back, or groin.","Slipping surface or cones sliding into the athlete path.","Repeated uncontrolled knee valgus or trunk collapse.","Athlete cannot remember route or react safely.","Fatigue changes braking mechanics."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Restore breathing","Cooldown mobility"],"pairs_well_after":["Output speed/COD block","Capacity strength block","Resilience braking block"],"good_for_sessions":["conditioning_intervals","general_warmup","landing_prep"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Athlete has pain or loss of control during warm-up.","Surface is slippery or space is crowded.","The session goal is recovery or restore only.","Before sprinting, jumping, skill learning, or heavy strength work."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["https://www.youtube.com/watch?v=yBKmTZ1XEOk","https://www.youtube.com/watch?v=e6uGs7Tw_bM","https://www.youtube.com/watch?v=swPWW_WmhCU","https://www.youtube.com/watch?v=_oJRFrj_gVc","https://www.youtube.com/watch?v=leJALwttReI"],"internal_notes":["Film one front/diagonal angle and one side angle when possible.","Show the cone layout before the rep.","Capture one slow walk-through, then one quality-speed rep.","For client view, keep the demo focused on setup, route, posture, and stop/cut standard."]}'::jsonb,
  updated_at = now()
WHERE slug = 'cone-gauntlet-quality-intervals';

