  recommended_age_min, recommended_age_max, attention_demand, notes, source
)
SELECT e.id, 5, 6, 5, 6,
  11, NULL::integer, 'moderate', 'Typical for ages 11+ when cone spacing, approach speed, and decision complexity are scaled. Overall difficulty reflects technical=5, load=6, complexity=5.', 'authored'
FROM coaching.exercise e
WHERE e.slug = 'cone-gauntlet-quality-intervals'
ON CONFLICT (exercise_id) DO UPDATE SET
  technical = EXCLUDED.technical,
  load = EXCLUDED.load,
  complexity = EXCLUDED.complexity,
  overall = EXCLUDED.overall,
  recommended_age_min = EXCLUDED.recommended_age_min,
  attention_demand = EXCLUDED.attention_demand,
  notes = EXCLUDED.notes,
  source = EXCLUDED.source,
  updated_at = now();

-- Refresh weighted taxonomy tags
