-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Cone drills build route learning, braking quality, and perception-action skill when dosed for the tagged phase.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('cone-march-line', 'This is the lowest-risk way to connect upright posture, arm timing, dorsiflexion, and foot strike before faster cone runs.', 'It belongs in Movement Intelligence because the value is route learning, rhythm, spacing, and perception before fatigue.', 'After Prepare & Access and before Output. Use while athletes are fresh enough to learn rhythm, route, and body position.', 'Do not race it before the athlete owns the route and rhythm; sloppy speed teaches the wrong pattern.', 'Reduce speed before reducing the learning goal; scale cone spacing, approach velocity, cut angle, and decision complexity.'),
  ('cone-skip-rhythm-build', 'Skips teach stiffness, rhythm, and coordination while staying technical enough for youth athletes.', 'It belongs in Movement Intelligence because the value is route learning, rhythm, spacing, and perception before fatigue.', 'After Prepare & Access and before Output. Use while athletes are fresh enough to learn rhythm, route, and body position.', 'Do not race it before the athlete owns the route and rhythm; sloppy speed teaches the wrong pattern.', 'Reduce speed before reducing the learning goal; scale cone spacing, approach velocity, cut angle, and decision complexity.'),
  ('a-skip-through-cone-gates', 'The gates constrain rhythm and step length without over-coaching, making sprint mechanics more visible.', 'It belongs in Movement Intelligence because the value is route learning, rhythm, spacing, and perception before fatigue.', 'After Prepare & Access and before Output. Use while athletes are fresh enough to learn rhythm, route, and body position.', 'Do not race it before the athlete owns the route and rhythm; sloppy speed teaches the wrong pattern.', 'Reduce speed before reducing the learning goal; scale cone spacing, approach velocity, cut angle, and decision complexity.'),
  ('falling-start-to-10-yard-cone', 'The forward fall creates a simple projection constraint so the athlete learns to push the ground back instead of popping up.', 'It belongs in Output because the value is high-quality speed, acceleration, reacceleration, or COD power with full recovery.', 'Early main-session Output block after warm-up and skill prep. Use low volume, high intent, and full rest before strength or conditioning.', 'Do not turn this into a conditioning finisher. If rest is short and cuts get sloppy, it is no longer an Output drill.', 'Reduce speed before reducing the learning goal; scale cone spacing, approach velocity, cut angle, and decision complexity.'),
  ('split-stance-10-yard-acceleration', 'The split stance exposes push-off asymmetries and lets the coach cue shin angle, torso angle, and arm drive.', 'It belongs in Output because the value is high-quality speed, acceleration, reacceleration, or COD power with full recovery.', 'Early main-session Output block after warm-up and skill prep. Use low volume, high intent, and full rest before strength or conditioning.', 'Do not turn this into a conditioning finisher. If rest is short and cuts get sloppy, it is no longer an Output drill.', 'Reduce speed before reducing the learning goal; scale cone spacing, approach velocity, cut angle, and decision complexity.'),
  ('push-up-start-to-cone', 'The floor start teaches fast organization from the ground while preserving a short, high-quality sprint distance.', 'It belongs in Output because the value is high-quality speed, acceleration, reacceleration, or COD power with full recovery.', 'Early main-session Output block after warm-up and skill prep. Use low volume, high intent, and full rest before strength or conditioning.', 'Do not turn this into a conditioning finisher. If rest is short and cuts get sloppy, it is no longer an Output drill.', 'Reduce speed before reducing the learning goal; scale cone spacing, approach velocity, cut angle, and decision complexity.'),
  ('crossover-step-to-sprint-cone', 'Many sport accelerations start laterally; this drill connects crossover mechanics to actual sprint projection.', 'It belongs in Output because the value is high-quality speed, acceleration, reacceleration, or COD power with full recovery.', 'Early main-session Output block after warm-up and skill prep. Use low volume, high intent, and full rest before strength or conditioning.', 'Do not turn this into a conditioning finisher. If rest is short and cuts get sloppy, it is no longer an Output drill.', 'Reduce speed before reducing the learning goal; scale cone spacing, approach velocity, cut angle, and decision complexity.'),
  ('curve-run-around-cone-arc', 'Curved running teaches inside-edge control and trunk lean without forcing a hard cut.', 'It belongs in Movement Intelligence because the value is route learning, rhythm, spacing, and perception before fatigue.', 'After Prepare & Access and before Output. Use while athletes are fresh enough to learn rhythm, route, and body position.', 'Do not race it before the athlete owns the route and rhythm; sloppy speed teaches the wrong pattern.', 'Reduce speed before reducing the learning goal; scale cone spacing, approach velocity, cut angle, and decision complexity.'),
  ('20-20-20-build-up-sprint', 'A progressive build gives athletes high-speed exposure without forcing a violent max start.', 'It belongs in Output because the value is high-quality speed, acceleration, reacceleration, or COD power with full recovery.', 'Early main-session Output block after warm-up and skill prep. Use low volume, high intent, and full rest before strength or conditioning.', 'Do not turn this into a conditioning finisher. If rest is short and cuts get sloppy, it is no longer an Output drill.', 'Reduce speed before reducing the learning goal; scale cone spacing, approach velocity, cut angle, and decision complexity.'),
  ('fly-zone-cone-sprint', 'The fly zone lets the coach time or observe upright mechanics while keeping volume low and rest high.', 'It belongs in Output because the value is high-quality speed, acceleration, reacceleration, or COD power with full recovery.', 'Early main-session Output block after warm-up and skill prep. Use low volume, high intent, and full rest before strength or conditioning.', 'Do not turn this into a conditioning finisher. If rest is short and cuts get sloppy, it is no longer an Output drill.', 'Reduce speed before reducing the learning goal; scale cone spacing, approach velocity, cut angle, and decision complexity.'),
  ('sprint-to-stick-deceleration', 'Athletes learn to lower the center of mass and distribute braking over several steps before harder COD drills.', 'It belongs in Resilience because the value is controlled braking, balance, joint ownership, and tissue tolerance.', 'After warm-up and before or after lower-level COD work when the goal is braking quality, not max speed.', 'Do not chase speed or volume before the athlete can stick the stop with clean knee and hip control.', 'Reduce speed before reducing the learning goal; scale cone spacing, approach velocity, cut angle, and decision complexity.'),
  ('backpedal-to-stick', 'Backward deceleration appears in field and court sports and teaches foot-under-hip control without max speed.', 'It belongs in Resilience because the value is controlled braking, balance, joint ownership, and tissue tolerance.', 'After warm-up and before or after lower-level COD work when the goal is braking quality, not max speed.', 'Do not chase speed or volume before the athlete can stick the stop with clean knee and hip control.', 'Reduce speed before reducing the learning goal; scale cone spacing, approach velocity, cut angle, and decision complexity.'),
  ('lateral-shuffle-to-stick', 'The stop exposes knee collapse and overreaching before athletes cut, mirror, or chase.', 'It belongs in Resilience because the value is controlled braking, balance, joint ownership, and tissue tolerance.', 'After warm-up and before or after lower-level COD work when the goal is braking quality, not max speed.', 'Do not chase speed or volume before the athlete can stick the stop with clean knee and hip control.', 'Reduce speed before reducing the learning goal; scale cone spacing, approach velocity, cut angle, and decision complexity.'),
  ('45-degree-cut-and-stick', 'The 45-degree angle teaches useful redirection without the stress of a full 90-degree cut.', 'It belongs in Resilience because the value is controlled braking, balance, joint ownership, and tissue tolerance.', 'After warm-up and before or after lower-level COD work when the goal is braking quality, not max speed.', 'Do not chase speed or volume before the athlete can stick the stop with clean knee and hip control.', 'Reduce speed before reducing the learning goal; scale cone spacing, approach velocity, cut angle, and decision complexity.'),
  ('90-degree-cut-and-stick', 'Sticking the 90-degree cut teaches the athlete to own the plant before chasing faster times.', 'It belongs in Resilience because the value is controlled braking, balance, joint ownership, and tissue tolerance.', 'After warm-up and before or after lower-level COD work when the goal is braking quality, not max speed.', 'Do not chase speed or volume before the athlete can stick the stop with clean knee and hip control.', 'Reduce speed before reducing the learning goal; scale cone spacing, approach velocity, cut angle, and decision complexity.'),
  ('decel-to-reaccelerate-gate', 'It links braking to the next acceleration, which is the real sport demand of COD.', 'It belongs in Output because the value is high-quality speed, acceleration, reacceleration, or COD power with full recovery.', 'Early main-session Output block after warm-up and skill prep. Use low volume, high intent, and full rest before strength or conditioning.', 'Do not turn this into a conditioning finisher. If rest is short and cuts get sloppy, it is no longer an Output drill.', 'Reduce speed before reducing the learning goal; scale cone spacing, approach velocity, cut angle, and decision complexity.'),
  ('single-leg-cone-reach-stick', 'This low-speed drill gives the ankle, knee, and hip the control needed for later cuts.', 'It belongs in Resilience because the value is controlled braking, balance, joint ownership, and tissue tolerance.', 'After warm-up and before or after lower-level COD work when the goal is braking quality, not max speed.', 'Do not chase speed or volume before the athlete can stick the stop with clean knee and hip control.', 'Reduce speed before reducing the learning goal; scale cone spacing, approach velocity, cut angle, and decision complexity.'),
